/*
 * three.min.js — LOCAL BUNDLE PLACEHOLDER
 * --------------------------------------------------------------------------
 * This file is intended to hold a local copy of Three.js r168 so the app
 * can run fully offline. It could NOT be downloaded in the build environment
 * because outbound network access to the CDNs was blocked (egress allowlist).
 *
 * To populate it, run ONE of the following from the project directory:
 *   curl -L https://cdnjs.cloudflare.com/ajax/libs/three.js/r168/three.min.js -o three.min.js
 *   curl -L https://unpkg.com/three@0.168.0/build/three.min.js -o three.min.js
 *   curl -L https://cdn.jsdelivr.net/npm/three@0.168.0/build/three.min.js -o three.min.js
 *
 * Until then this placeholder intentionally does NOT define `window.THREE`,
 * so the CDN fallback loader in index.html (which targets r168) takes over
 * automatically and the app keeps working online.
 */
